const getOrigin = (value) => {
  const text = String(value ?? '').trim();
  const match = text.match(/^https?:\/\/[^/]+/i);
  return match ? match[0] : null;
};
const settings = $input.first().json ?? {};
const incoming = $('When Executed by Another Workflow').first()?.json ?? $('When clicking \'Execute workflow\'').first()?.json ?? {};
const defaultTargetUrl = 'https://clubspark.lta.org.uk/AvondaleTennisClub/Admin/Contacts';
const targetUrl = String(incoming.targetUrl ?? defaultTargetUrl).trim() || defaultTargetUrl;
const targetOrigin = getOrigin(targetUrl);
const forceRefresh = [true, 'true', '1', 1, 'yes'].includes(incoming.forceRefresh);
const requestedMaxAge = Number.parseFloat(String(incoming.maxAgeMinutes ?? incoming.cacheMaxAgeMinutes ?? '20'));
const maxAgeMinutes = Number.isFinite(requestedMaxAge) && requestedMaxAge > 0 ? requestedMaxAge : 20;
const providedCookieHeader = typeof incoming.cookieHeader === 'string' ? incoming.cookieHeader.trim() : '';
const providedUserAgent = typeof incoming.userAgent === 'string' ? incoming.userAgent.trim() : '';
const hasProvidedSession = Boolean(!forceRefresh && providedCookieHeader && providedUserAgent);
const staticData = $getWorkflowStaticData('global');
const fetchedAtMs = staticData.fetchedAt ? Date.parse(staticData.fetchedAt) : NaN;
let sameOrigin = true;
try {
  const cachedOrigin = staticData.sessionOrigin ?? (staticData.targetUrl ? getOrigin(staticData.targetUrl) : null);
  sameOrigin = cachedOrigin && targetOrigin ? cachedOrigin === targetOrigin : true;
} catch {
  sameOrigin = false;
}
const hasCachedSession = Boolean(
  !hasProvidedSession
  && !forceRefresh
  && staticData.cookieHeader
  && staticData.userAgent
  && Number.isFinite(fetchedAtMs)
  && (Date.now() - fetchedAtMs) <= (maxAgeMinutes * 60 * 1000)
  && sameOrigin
);
return [{
  json: {
    clubspark_exporter_base_url: settings.clubspark_exporter_base_url,
    targetUrl,
    maxAgeMinutes,
    forceRefresh,
    useCachedSession: hasProvidedSession || hasCachedSession,
    authenticated: (hasProvidedSession || hasCachedSession) ? true : undefined,
    authenticatedUrl: hasProvidedSession
      ? (incoming.authenticatedUrl ?? targetUrl)
      : hasCachedSession
        ? (staticData.authenticatedUrl ?? targetUrl)
        : undefined,
    pageTitle: hasProvidedSession
      ? (incoming.pageTitle ?? null)
      : hasCachedSession
        ? (staticData.pageTitle ?? null)
        : undefined,
    userAgent: hasProvidedSession ? providedUserAgent : hasCachedSession ? staticData.userAgent : undefined,
    cookieHeader: hasProvidedSession ? providedCookieHeader : hasCachedSession ? staticData.cookieHeader : undefined,
    cookieCount: hasProvidedSession
      ? Number(incoming.cookieCount ?? 0)
      : hasCachedSession
        ? Number(staticData.cookieCount ?? 0)
        : undefined,
    probe: hasProvidedSession
      ? {
          source: 'input_session',
          targetOrigin,
        }
      : hasCachedSession
        ? {
            source: 'workflow_static_data',
            fetchedAt: staticData.fetchedAt ?? null,
            maxAgeMinutes,
            targetOrigin,
          }
        : null,
  },
}];

const getOrigin = (value) => {
  const text = String(value ?? '').trim();
  const match = text.match(/^https?:\/\/[^/]+/i);
  return match ? match[0] : null;
};
const payload = $input.first().json ?? {};
if (payload.authenticated !== true || !payload.cookieHeader || !payload.userAgent) {
  throw new Error('ClubSpark auth session did not return a reusable authenticated session.');
}
const staticData = $getWorkflowStaticData('global');
staticData.fetchedAt = new Date().toISOString();
staticData.targetUrl = payload.targetUrl ?? null;
staticData.sessionOrigin = payload.targetUrl ? getOrigin(payload.targetUrl) : null;
staticData.authenticatedUrl = payload.authenticatedUrl ?? payload.targetUrl ?? null;
staticData.pageTitle = payload.pageTitle ?? null;
staticData.userAgent = payload.userAgent;
staticData.cookieHeader = payload.cookieHeader;
staticData.cookieCount = Number(payload.cookieCount ?? 0);
return [{ json: payload }];

const payload = $input.first().json ?? {};
if (!payload.cookieHeader) {
  throw new Error('ClubSpark auth session did not return a reusable cookie header.');
}
if (payload.authenticated !== true) {
  throw new Error('ClubSpark auth session did not report authenticated=true.');
}
return [{
  json: {
    authenticated: payload.authenticated,
    targetUrl: payload.targetUrl,
    authenticatedUrl: payload.authenticatedUrl,
    pageTitle: payload.pageTitle,
    userAgent: payload.userAgent,
    cookieHeader: payload.cookieHeader,
    cookieCount: payload.cookieCount,
    probe: payload.probe ?? null,
  },
}];
